### Tool class — `WeatherTools.cs`

```csharp
using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Text.Json;

[McpServerToolType]
public class WeatherTools(HttpClient httpClient, ILogger<WeatherTools> logger)
{
    private const string BaseUrl = "https://api.weather.gov";

    [McpServerTool(ReadOnly = true), Description("Get the current weather forecast for a US location by latitude and longitude.")]
    public async Task<string> GetForecast(
        [Description("Latitude of the location (e.g. 39.7456)")] double latitude,
        [Description("Longitude of the location (e.g. -97.0892)")] double longitude,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching forecast for ({Lat}, {Lon})", latitude, longitude);

        var pointUrl = $"{BaseUrl}/points/{latitude},{longitude}";
        var pointJson = await httpClient.GetStringAsync(pointUrl, cancellationToken);
        var forecastUrl = JsonDocument.Parse(pointJson)
            .RootElement.GetProperty("properties")
            .GetProperty("forecast").GetString()!;

        var forecastJson = await httpClient.GetStringAsync(forecastUrl, cancellationToken);
        var periods = JsonDocument.Parse(forecastJson)
            .RootElement.GetProperty("properties")
            .GetProperty("periods");

        var results = new List<string>();
        foreach (var p in periods.EnumerateArray().Take(3))
        {
            results.Add($"{p.GetProperty("name")}: " +
                         $"{p.GetProperty("temperature")}°{p.GetProperty("temperatureUnit")} — " +
                         $"{p.GetProperty("detailedForecast")}");
        }
        return string.Join("\n\n", results);
    }

    [McpServerTool(ReadOnly = true), Description("Get active weather alerts for a US state.")]
    public async Task<string> GetAlerts(
        [Description("Two-letter US state code (e.g. 'KS', 'CA')")] string state,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching alerts for state {State}", state);

        var url = $"{BaseUrl}/alerts/active/area/{state.ToUpperInvariant()}";
        var json = await httpClient.GetStringAsync(url, cancellationToken);
        var features = JsonDocument.Parse(json)
            .RootElement.GetProperty("features");

        if (features.GetArrayLength() == 0)
            return $"No active alerts for {state.ToUpperInvariant()}.";

        var alerts = new List<string>();
        foreach (var f in features.EnumerateArray().Take(5))
        {
            var props = f.GetProperty("properties");
            alerts.Add($"⚠ {props.GetProperty("headline")}\n" +
                       $"  Severity: {props.GetProperty("severity")}\n" +
                       $"  {props.GetProperty("description")}");
        }
        return string.Join("\n\n", alerts);
    }
}
```

### Entry point — `Program.cs`

```csharp
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;

var builder = Host.CreateApplicationBuilder(args);

// CRITICAL: stdio transport uses stdout for JSON-RPC — all logs must go to stderr
builder.Logging.AddConsole(options =>
    options.LogToStandardErrorThreshold = LogLevel.Trace);

builder.Services.AddHttpClient();   // registers IHttpClientFactory + HttpClient for DI

builder.Services.AddMcpServer()
    .WithStdioServerTransport()
    .WithToolsFromAssembly();        // discovers all [McpServerToolType] classes

await builder.Build().RunAsync();
```

---

### How DI works for MCP tools

The SDK resolves parameters in two layers:

| Injection style | How it works |
|---|---|
| **Constructor injection** | Make the tool class **non-static** with a primary constructor. Register services in `Program.cs` (`AddHttpClient()`, etc.). The SDK creates an instance per call, injecting resolved services. |
| **Method parameter injection** | Any parameter whose type is registered in DI (or is a framework type like `CancellationToken`, `IMcpServer`, `IProgress<T>`) is injected automatically and **hidden from the tool schema**. Only parameters with `[Description]` appear in the schema the LLM sees. |

So in the example above, `HttpClient` and `ILogger<WeatherTools>` come from DI — the LLM only sees `latitude`, `longitude`, and `state` as callable parameters.

**Key rules:**
- `AddHttpClient()` registers both `IHttpClientFactory` and `HttpClient` for injection.
- `ILogger<T>` is registered by default — no extra setup.
- Mark tools `ReadOnly = true` when they don't mutate state (helps LLM reasoning).
- Always accept `CancellationToken` in async tools for cooperative cancellation.
